+    fn hash_key(source_path: &str) -> u64 {
+        fxhash::hash64(source_path)
+    }
+
+    /// Get the shard index for a given hash.
+    #[inline]
+    fn shard_index(hash: u64) -> usize {
+        (hash as usize) % NUM_SHARDS
+    }
